```ts
type Contra<T> = T extends {
  a: (x: infer U) => void;
  b: (x: infer U) => void;
}
  ? U
  : never;

type R = Contra<{ a: (x: string) => void; b: (x: number) => void }>;
```

```ts
type Getters<T> = {
  [K in keyof T as `get${Capitalize<string & K>}`]: () => T[K];
};

type R = Getters<{ name: string; age: number }>;
```

```ts
